  `${SYMBOL}@ticker`,     // price tick
  `${SYMBOL}@depth10`,    // order book
  `${SYMBOL}@kline_1m`,   // 1m candle
].join('/')

const WS_URL = `wss://stream.binance.com:9443/stream?streams=${STREAMS}`

const ws = new WebSocket(WS_URL)

ws.on('open', () => {
  console.log('Connected to Binance')
})

ws.on('message', (raw) => {
  const msg = JSON.parse(raw)
  handleMessage(msg.stream, msg.data)
})

ws.on('error', (err) => {
  console.error('WebSocket error:', err.message)
})

ws.on('close', () => {
  console.log('Disconnected')
})

function handleMessage(stream, data) {
  if (stream.endsWith('@ticker')) {
    console.log(`Price: $${data.c}  Change: ${data.P}%`)
  }
}

function handleMessage(stream, data) {

  // ── 24hr ticker ──────────────────────── //
  if (stream.endsWith('@ticker')) {
    const tick = {
      symbol:    'BTC/USDT',
      price:     parseFloat(data.c),
      change:    parseFloat(data.p),
      changePct: parseFloat(data.P),
      high24h:   parseFloat(data.h),
      low24h:    parseFloat(data.l),
      volume:    parseFloat(data.v),
      bid:       parseFloat(data.b),
      ask:       parseFloat(data.a),
    }
    console.log(`[TICK] $${tick.price}  ${tick.changePct > 0 ? '+' : ''}${tick.changePct}%`)
    return
  }

  // ── Order book ────────────────────────── //
  if (stream.includes('@depth')) {
    const bestBid = parseFloat(data.bids[0][0])
    const bestAsk = parseFloat(data.asks[0][0])
    const spread  = (bestAsk - bestBid).toFixed(2)
    console.log(`[BOOK] Bid: $${bestBid}  Ask: $${bestAsk}  Spread: $${spread}`)
    return
  }

  // ── Candlestick ───────────────────────── //
  if (stream.includes('@kline_')) {
    const k = data.k
    console.log(
      `[CANDLE] O:${k.o} H:${k.h} L:${k.l} C:${k.c}` +
      (k.x ? ' [CLOSED]' : ' [OPEN]')
    )
    return
  }
}

const WebSocket = require('ws')

const SYMBOL  = 'btcusdt'
const STREAMS = [
  `${SYMBOL}@ticker`,
  `${SYMBOL}@depth10`,
  `${SYMBOL}@kline_1m`,
].join('/')

const WS_URL       = `wss://stream.binance.com:9443/stream?streams=${STREAMS}`
const MAX_RETRIES  = 5
let   retryCount   = 0
let   ws           = null

function connect() {
  ws = new WebSocket(WS_URL)

  ws.on('open', () => {
    console.log('Connected to Binance')
    retryCount = 0   // reset on successful connect
  })

  ws.on('message', (raw) => {
    const msg = JSON.parse(raw)
    handleMessage(msg.stream, msg.data)
  })

  ws.on('error', (err) => {
    console.error('WebSocket error:', err.message)
  })

  ws.on('close', () => {
    if (retryCount >= MAX_RETRIES) {
      console.error('Max reconnect attempts reached')
      return
    }
    retryCount++
    const delay = 3000 * retryCount
    console.log(`Reconnecting in ${delay}ms... (attempt ${retryCount})`)
    setTimeout(connect, delay)
  })
}

connect()

